'use client';

import { Accessibility, BookOpen, CalendarDays, CheckCircle2, ChevronLeft, ChevronRight, Code2, Contrast, Copy, CreativeCommons, Download, ExternalLink, Eye, FileText, Lightbulb, MonitorSmartphone, Printer, Route, ShieldCheck, Type, UserRound, Users, Volume2 } from 'lucide-react';
import Image from 'next/image';
import { useState, useSyncExternalStore } from 'react';
import TextoConGlosario from '@/componentes/TextoConGlosario';
import ZonaActiva from '@/componentes/ZonaActiva';
import { casosRealesPhishing, crearActividades, crearEjercicios, grados, herramientasPorUnidad, niveles, principiosLaboratorio, recursosAgesicPorUnidad, saberesPorUnidad } from '@/contenido/ciberseguridad';
import { glosario, obtenerEntradasGlosario } from '@/contenido/glosario';
import type { Grado, Unidad } from '@/contenido/ciberseguridad';

const baseAssets = process.env.NEXT_PUBLIC_REA_BASE_PATH ?? '';
const urlPublica = (process.env.NEXT_PUBLIC_REA_PUBLIC_URL ?? 'https://contenidistas.github.io/modulo-ciberseguridad-ebi/').replace(/\/$/, '');
const urlPrograma = 'https://www.anep.edu.uy/sites/default/files/images/te-programas/2024/ajustes/3er_ciclo/Ciencias%20de%20la%20Computaci%C3%B3n%20-%20Tramo%205%20-%202024.pdf';
const urlCulturaCiberseguridad = 'https://www.gub.uy/agencia-gobierno-electronico-sociedad-informacion-conocimiento/comunicacion/publicaciones/estrategia-nacional-ciberseguridad-del-uruguay-2024-2030/pilares/pilar-6';
const subscribe = (callback: () => void) => {
  window.addEventListener('popstate', callback);
  return () => window.removeEventListener('popstate', callback);
};
const snapshot = () => `${window.location.pathname}${window.location.search}`;
const snapshotServidor = () => '';
const escapar = (texto: string) => texto.replace(/[&<>'"]/g, (caracter) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;' })[caracter] ?? caracter);

const descargar = (contenido: string, nombre: string, tipo = 'text/html;charset=utf-8') => {
  const url = URL.createObjectURL(new Blob([contenido], { type: tipo }));
  const enlace = document.createElement('a');
  enlace.href = url;
  enlace.download = nombre;
  enlace.click();
  URL.revokeObjectURL(url);
};

const sugerenciasDocentes = [
  'Recoge primero decisiones individuales sin calificarlas. Pregunta qué emoción, expectativa o señal inclinó cada respuesta.',
  'Distribuye casos diferentes entre los equipos y solicita distinguir evidencia, inferencia y dato faltante antes de compartir conclusiones.',
  'Haz que cada grupo pruebe su protocolo con más de un caso. Retroalimenta la secuencia de decisiones y no solo el resultado final.',
  'Ofrece elección de formato y verifica accesibilidad, claridad del canal oficial y ausencia de enlaces, datos o instrucciones riesgosas.',
];

const pasosCapsula = [
  { titulo: 'Me ubico', breve: 'Propósito y opciones' },
  { titulo: 'Identifico', breve: 'Lo que ya sé' },
  { titulo: 'Aprendo', breve: 'Ideas y ejemplos' },
  { titulo: 'Comprendo', breve: 'El desafío' },
  { titulo: 'Practico', breve: 'Ensayo con apoyo' },
  { titulo: 'Consulto', breve: 'Herramientas y fuentes' },
  { titulo: 'Compruebo', breve: 'Zona activa y cierre' },
];

function CabeceraPaso({ numero, titulo, descripcion }: { numero: number; titulo: string; descripcion: string }) {
  return <div className="mb-6 flex items-start gap-4 border-b border-sky-200 pb-4"><span className="inline-flex h-9 w-9 shrink-0 items-center justify-center rounded-md bg-[#0069aa] text-sm font-black text-white">{numero}</span><div><p className="text-xs font-black uppercase text-[#c65f00]">Paso {numero} de {pasosCapsula.length}</p><h3 className="mt-1 text-2xl font-black text-slate-950">{titulo}</h3><p className="mt-1 text-sm leading-6 text-slate-600">{descripcion}</p></div></div>;
}

function Controles({ contraste, textoGrande, lecturaActiva, onContraste, onTexto, onLectura }: { contraste: boolean; textoGrande: boolean; lecturaActiva: boolean; onContraste: () => void; onTexto: () => void; onLectura: () => void }) {
  return (
    <div className="flex items-center gap-1 rounded-lg border border-sky-100 bg-white p-1" aria-label="Controles de accesibilidad">
      <button type="button" aria-pressed={contraste} onClick={onContraste} title="Alternar alto contraste" className={`inline-flex h-10 w-10 items-center justify-center rounded-md ${contraste ? 'bg-[#0069aa] text-white' : 'text-[#0069aa] hover:bg-sky-50'}`}><Contrast size={17} /></button>
      <button type="button" aria-pressed={textoGrande} onClick={onTexto} title="Alternar texto grande" className={`inline-flex h-10 w-10 items-center justify-center rounded-md ${textoGrande ? 'bg-[#0069aa] text-white' : 'text-[#0069aa] hover:bg-sky-50'}`}><Type size={17} /></button>
      <button type="button" aria-pressed={lecturaActiva} onClick={onLectura} title={lecturaActiva ? 'Detener lectura' : 'Leer página'} className={`inline-flex h-10 w-10 items-center justify-center rounded-md ${lecturaActiva ? 'bg-[#0069aa] text-white' : 'text-[#0069aa] hover:bg-sky-50'}`}><Volume2 size={17} /></button>
    </div>
  );
}

function Encabezado({ grado, interfaz, cambiarGrado, volver, controles, seccionActiva, irASeccion }: { grado: Grado; interfaz: 'docente' | 'alumno'; cambiarGrado: (grado: Grado) => void; volver?: () => void; controles: React.ReactNode; seccionActiva?: string; irASeccion?: (id: string) => void }) {
  return (
    <header className="border-b border-sky-100 bg-white">
      <div className="mx-auto flex max-w-6xl flex-col gap-4 px-4 py-5 md:px-8">
        <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div className="flex items-center gap-4">
            <Image src={`${baseAssets}/logoedytic.jpg`} alt="Logo EDyTIC" width={112} height={56} className="h-14 w-28 rounded-lg border border-sky-100 bg-white object-contain p-2" priority />
            <div>
              <p className="text-xs font-black uppercase text-[#c66b00]">Recurso {interfaz === 'docente' ? 'docente' : 'estudiantil'} · Ciberseguridad EBI</p>
              <h1 className="mt-1 text-2xl font-black text-[#0069aa] sm:text-3xl">{interfaz === 'docente' ? `Planificación para ${niveles[grado].etiqueta.replace(' EBI', '')} año` : 'Ciberseguridad y protección de datos'}</h1>
            </div>
          </div>
          <div className="no-print flex flex-wrap items-center gap-2">
            {controles}
            <nav className="inline-flex rounded-lg border border-sky-100 bg-sky-50 p-1" aria-label="Niveles">
              {grados.map((item) => grado === item ? <span key={item} className="rounded-md bg-[#0069aa] px-3 py-2 text-sm font-bold text-white" aria-current="page">{niveles[item].etiqueta.replace(' EBI', '')}</span> : <button key={item} type="button" onClick={() => cambiarGrado(item)} className="rounded-md px-3 py-2 text-sm font-bold text-slate-600">{niveles[item].etiqueta.replace(' EBI', '')}</button>)}
            </nav>
            {interfaz === 'docente' && <button type="button" onClick={() => window.print()} className="inline-flex h-10 w-10 items-center justify-center rounded-lg border border-sky-100 bg-white text-[#0069aa]" aria-label="Imprimir planificación" title="Imprimir planificación"><Printer size={17} /></button>}
            {volver && <button type="button" onClick={volver} className="inline-flex items-center gap-2 rounded-lg border border-sky-100 bg-white px-3 py-2 text-sm font-bold text-[#0069aa]"><BookOpen size={16} />Guía docente</button>}
          </div>
        </div>
        {interfaz === 'docente' && irASeccion && <nav className="no-print flex gap-2 overflow-x-auto pb-1 text-sm font-bold" aria-label="Secciones del recurso">
          {[['fundamentacion', 'Fundamentación'], ['programa', 'Programa'], ['uso', 'Cómo utilizarlo'], ['dua', 'DUA'], ['etica', 'Ética y seguridad'], ['unidades', 'Unidades']].map(([id, etiqueta]) => <button key={id} type="button" onClick={() => irASeccion(id)} aria-pressed={seccionActiva === id} className={`whitespace-nowrap rounded-lg border px-4 py-2.5 transition ${seccionActiva === id ? 'border-[#0069aa] bg-[#0069aa] text-white' : 'border-slate-200 bg-white text-slate-700 hover:border-sky-300'}`}>{etiqueta}</button>)}
        </nav>}
      </div>
    </header>
  );
}

function LaboratorioSeguro({ id, className = '' }: { id?: string; className?: string }) {
  return (
    <section id={id} className={`border-y border-emerald-200 bg-emerald-50 py-6 ${className}`} aria-labelledby="laboratorio-seguro">
      <div className="mx-auto max-w-6xl px-4 md:px-8">
        <div className="grid gap-5 lg:grid-cols-[0.35fr_1fr]">
          <div><ShieldCheck className="text-[#167451]" size={30} /><h2 id="laboratorio-seguro" className="mt-2 text-xl font-black text-emerald-950">Laboratorio seguro</h2></div>
          <ul className="grid gap-2 sm:grid-cols-2">{principiosLaboratorio.map((principio) => <li key={principio} className="flex gap-2 text-sm leading-6 text-emerald-950"><CheckCircle2 className="mt-1 shrink-0" size={16} />{principio}</li>)}</ul>
        </div>
      </div>
    </section>
  );
}

export default function Home() {
  const urlActual = useSyncExternalStore(subscribe, snapshot, snapshotServidor);
  const parametros = new URLSearchParams(urlActual.split('?')[1] ?? '');
  const gradoParametro = parametros.get('grado');
  const grado: Grado = grados.includes(gradoParametro as Grado) ? gradoParametro as Grado : '7mo';
  const interfaz = parametros.get('interfaz') === 'alumno' ? 'alumno' : 'docente';
  const nivel = niveles[grado];
  const unidadParametro = parametros.get('unidad');
  const unidad = nivel.unidades.find((item) => item.id === unidadParametro) ?? nivel.unidades[0];
  const saber = saberesPorUnidad[unidad.id];
  const herramientas = herramientasPorUnidad[unidad.id] ?? [];
  const recursosAgesic = recursosAgesicPorUnidad[unidad.id] ?? [];
  const actividades = crearActividades(unidad);
  const ejercicios = crearEjercicios(unidad);
  const entradasGlosario = obtenerEntradasGlosario([unidad.proposito, unidad.situacion, saber.ideaCentral, saber.explicacion, ...unidad.conceptos, ...saber.ejemplos.flatMap((ejemplo) => [ejemplo.situacion, ejemplo.lectura, ejemplo.decision]), ...(saber.ampliaciones ?? []).flatMap((ampliacion) => [ampliacion.titulo, ampliacion.explicacion, ampliacion.ejemplo, ampliacion.cuidado]), ...actividades.map((actividad) => actividad.consigna)]);
  const terminosDeLaUnidad = new Set(entradasGlosario.map((entrada) => entrada.termino));
  const entradasGlosarioCompletas = [...entradasGlosario, ...glosario.filter((entrada) => !terminosDeLaUnidad.has(entrada.termino))];
  const [contraste, setContraste] = useState(false);
  const [textoGrande, setTextoGrande] = useState(false);
  const [lecturaActiva, setLecturaActiva] = useState(false);
  const [saberAudioActivo, setSaberAudioActivo] = useState(false);
  const [estadoCopia, setEstadoCopia] = useState('');
  const modoParametro = parametros.get('agrupamiento') === 'individual' ? 'individual' : 'pareja';
  const desafioParametro = parametros.get('desafio') === 'ampliado';
  const andamiajeParametro = Math.min(3, Math.max(0, Number(parametros.get('andamiaje') ?? 1) || 0));
  const [modoTrabajoLocal, setModoTrabajo] = useState<'individual' | 'pareja' | null>(null);
  const [desafioLocal, setDesafioAmpliado] = useState<boolean | null>(null);
  const [andamiajeLocal, setNivelAndamiaje] = useState<number | null>(null);
  const [pasoActivo, setPasoActivo] = useState(0);
  const [glosarioAbierto, setGlosarioAbierto] = useState(false);
  const modoTrabajo = modoTrabajoLocal ?? modoParametro;
  const desafioAmpliado = desafioLocal ?? desafioParametro;
  const nivelAndamiaje = andamiajeLocal ?? andamiajeParametro;
  const [seccionActiva, setSeccionActiva] = useState('fundamentacion');

  const alternarLectura = () => {
    if (!('speechSynthesis' in window)) return;
    if (lecturaActiva) {
      window.speechSynthesis.cancel();
      setLecturaActiva(false);
      return;
    }
    const contenido = document.querySelector('main')?.innerText ?? '';
    const lectura = new SpeechSynthesisUtterance(contenido);
    lectura.lang = 'es-UY';
    lectura.rate = 0.95;
    lectura.onend = () => setLecturaActiva(false);
    lectura.onerror = () => setLecturaActiva(false);
    window.speechSynthesis.cancel();
    window.speechSynthesis.speak(lectura);
    setLecturaActiva(true);
  };

  const alternarAudioSaber = () => {
    if (!('speechSynthesis' in window)) return;
    if (saberAudioActivo) {
      window.speechSynthesis.cancel();
      setSaberAudioActivo(false);
      return;
    }
    const ejemplos = saber.ejemplos.map((ejemplo) => `${ejemplo.titulo}. ${ejemplo.situacion} ${ejemplo.lectura} Decisión recomendada: ${ejemplo.decision}`).join(' ');
    const ampliaciones = (saber.ampliaciones ?? []).map((ampliacion) => `${ampliacion.titulo}. ${ampliacion.explicacion} Ejemplo: ${ampliacion.ejemplo} Cuidado: ${ampliacion.cuidado}`).join(' ');
    const lectura = new SpeechSynthesisUtterance(`${saber.ideaCentral} ${saber.explicacion} ${ejemplos} ${ampliaciones}`);
    lectura.lang = 'es-UY';
    lectura.rate = 0.92;
    lectura.onend = () => setSaberAudioActivo(false);
    lectura.onerror = () => setSaberAudioActivo(false);
    window.speechSynthesis.cancel();
    setLecturaActiva(false);
    window.speechSynthesis.speak(lectura);
    setSaberAudioActivo(true);
  };

  const irASeccion = (id: string) => {
    setSeccionActiva(id);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };
  const desplazarCasos = (id: string, direccion: -1 | 1) => {
    const carrusel = document.getElementById(id);
    carrusel?.scrollBy({ left: direccion * carrusel.clientWidth, behavior: 'smooth' });
  };
  const cambiarPaso = (indice: number) => {
    setPasoActivo(Math.min(pasosCapsula.length - 1, Math.max(0, indice)));
    window.setTimeout(() => document.getElementById('recorrido-capsula')?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 0);
  };
  const clasePaso = (indice: number) => `paso-capsula ${pasoActivo === indice ? 'paso-capsula-activo' : ''}`;
  const navegar = (cambios: Record<string, string | null>) => {
    const siguientes = new URLSearchParams(window.location.search);
    Object.entries(cambios).forEach(([clave, valor]) => valor === null ? siguientes.delete(clave) : siguientes.set(clave, valor));
    window.history.pushState(null, '', `${window.location.pathname}?${siguientes.toString()}`);
    window.dispatchEvent(new PopStateEvent('popstate'));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const cambiarGrado = (siguiente: Grado) => navegar({ grado: siguiente, unidad: niveles[siguiente].unidades[0].id });
  const urlAlumno = (publica = false) => {
    const query = new URLSearchParams({ grado, interfaz: 'alumno', unidad: unidad.id, agrupamiento: modoTrabajo, desafio: desafioAmpliado ? 'ampliado' : 'basico', andamiaje: String(nivelAndamiaje) });
    return `${publica ? urlPublica : window.location.pathname}?${query.toString()}`;
  };
  const copiarIframe = async () => {
    const iframe = `<iframe src="${urlAlumno(true)}" title="${unidad.titulo}" width="100%" height="900" loading="lazy" allow="clipboard-write" style="border:0"></iframe>`;
    try {
      await navigator.clipboard.writeText(iframe);
    } catch {
      const area = document.createElement('textarea'); area.value = iframe; document.body.append(area); area.select(); document.execCommand('copy'); area.remove();
    }
    setEstadoCopia('Iframe copiado para CREA');
    window.setTimeout(() => setEstadoCopia(''), 2500);
  };
  const htmlFicha = (seleccionada: Unidad) => `<!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Ficha docente - ${escapar(seleccionada.titulo)}</title><style>body{font-family:Arial;color:#172033;margin:0;background:#f6fafc}main{max-width:850px;margin:auto;padding:32px}h1,h2{color:#0069aa}section{background:white;border-left:4px solid #167451;margin:18px 0;padding:18px}p,li{line-height:1.6}.meta{color:#9a4f00;font-weight:bold}</style></head><body><main><p class="meta">Ficha docente · ${nivel.etiqueta}</p><h1>${escapar(seleccionada.titulo)}</h1><p>${escapar(seleccionada.referenciaPrograma)}</p><section><h2>Propósito</h2><p>${escapar(seleccionada.proposito)}</p><h2>Contenidos</h2><ul>${seleccionada.contenidosPrograma.map((item) => `<li>${escapar(item)}</li>`).join('')}</ul></section><section><h2>Actividad</h2><p>${escapar(seleccionada.situacion)}</p><p><strong>Producto:</strong> ${escapar(seleccionada.producto)}</p><p><strong>Evidencia:</strong> ${escapar(seleccionada.evidencia)}</p><p><strong>Criterio:</strong> ${escapar(seleccionada.criterio)}</p></section><section><h2>Uso en CREA</h2><p>Embeber la vista estudiantil y solicitar el producto sin datos personales reales. Usar únicamente casos ficticios y entornos autorizados.</p></section></main></body></html>`;
  const controles = <Controles contraste={contraste} textoGrande={textoGrande} lecturaActiva={lecturaActiva} onContraste={() => setContraste((valor) => !valor)} onTexto={() => setTextoGrande((valor) => !valor)} onLectura={alternarLectura} />;

  if (interfaz === 'alumno') {
    return (
      <main className="cyber-grid min-h-screen" data-contraste={contraste} data-texto={textoGrande ? 'grande' : 'normal'}>
        <Encabezado grado={grado} interfaz="alumno" cambiarGrado={cambiarGrado} volver={() => navegar({ interfaz: 'docente' })} controles={controles} />
        <div className="mx-auto max-w-4xl px-4 py-8 md:px-8">
          <p className="text-xs font-black uppercase text-[#c65f00]">{nivel.etiqueta} · Experiencia estudiantil</p>
          <h2 className="mt-2 text-3xl font-black text-slate-950">{unidad.titulo}</h2>
          <p className="mt-3 max-w-3xl text-lg leading-8 text-slate-700"><TextoConGlosario texto={unidad.proposito} /></p>
          <nav id="recorrido-capsula" className="no-print sticky top-0 z-20 mt-7 border-y border-sky-200 bg-white/95 py-3 backdrop-blur" aria-label="Recorrido de la cápsula"><div className="mb-3 flex items-center gap-3"><div className="h-1.5 flex-1 overflow-hidden rounded-full bg-sky-100"><div className="h-full bg-[#167451] transition-all" style={{ width: `${((pasoActivo + 1) / pasosCapsula.length) * 100}%` }} /></div><button type="button" onClick={() => setGlosarioAbierto((valor) => !valor)} aria-expanded={glosarioAbierto} aria-controls="glosario-capsula" className={`inline-flex shrink-0 items-center gap-2 rounded-md border px-3 py-1.5 text-xs font-black ${glosarioAbierto ? 'border-[#0069aa] bg-[#0069aa] text-white' : 'border-sky-200 bg-white text-[#0069aa]'}`}><BookOpen size={15} />Glosario</button></div><div className="flex gap-2 overflow-x-auto pb-1">{pasosCapsula.map((paso, indice) => <button key={paso.titulo} type="button" onClick={() => cambiarPaso(indice)} aria-current={pasoActivo === indice ? 'step' : undefined} className={`min-w-28 rounded-lg border px-3 py-2 text-left transition ${pasoActivo === indice ? 'border-[#0069aa] bg-[#0069aa] text-white' : indice < pasoActivo ? 'border-emerald-200 bg-emerald-50 text-emerald-900' : 'border-slate-200 bg-white text-slate-600'}`}><span className="block text-xs font-black">{indice + 1}. {paso.titulo}</span><span className={`mt-0.5 block text-[11px] ${pasoActivo === indice ? 'text-sky-100' : 'text-slate-500'}`}>{paso.breve}</span></button>)}</div></nav>
          {glosarioAbierto && <aside id="glosario-capsula" className="no-print mt-4 max-h-[70vh] overflow-y-auto rounded-lg border border-sky-200 bg-white p-5 shadow-lg shadow-sky-950/10" aria-labelledby="titulo-glosario"><div className="sticky top-0 z-10 flex items-start justify-between gap-4 border-b border-sky-100 bg-white pb-4"><div><p className="text-xs font-black uppercase text-[#c65f00]">Consulta rápida · {glosario.length} términos</p><h3 id="titulo-glosario" className="mt-1 text-xl font-black text-[#0069aa]">Glosario de ciberseguridad</h3><p className="mt-1 text-sm leading-6 text-slate-600">Los términos señalados como “En esta unidad” aparecen primero. También puedes enfocar o pasar el puntero sobre las palabras subrayadas.</p></div><button type="button" onClick={() => setGlosarioAbierto(false)} className="shrink-0 rounded-md border border-sky-200 px-3 py-2 text-xs font-black text-[#0069aa]">Cerrar</button></div><dl className="mt-5 grid gap-4 sm:grid-cols-2">{entradasGlosarioCompletas.map((entrada) => <div key={entrada.termino} className={`border-l-4 pl-3 ${terminosDeLaUnidad.has(entrada.termino) ? 'border-[#167451]' : 'border-sky-200'}`}><dt className="flex flex-wrap items-center gap-2 text-sm font-black text-slate-950">{entrada.termino}{terminosDeLaUnidad.has(entrada.termino) && <span className="rounded bg-emerald-50 px-1.5 py-0.5 text-[10px] uppercase text-[#167451]">En esta unidad</span>}</dt><dd className="mt-1 text-sm leading-6 text-slate-600">{entrada.definicion}</dd></div>)}</dl></aside>}
          <section className={`${clasePaso(0)} mt-8`} aria-labelledby="como-trabajar">
            <CabeceraPaso numero={1} titulo="Me ubico" descripcion="Reconoce qué aprenderás y elige cómo quieres recorrer la cápsula." />
          <section className="border-y border-sky-200 bg-white py-5">
            <div className="flex items-center gap-3"><Accessibility className="text-[#0069aa]" size={22} /><div><p className="text-xs font-black uppercase text-[#c65f00]">Opciones DUA</p><h3 id="como-trabajar" className="font-black text-slate-950">Cómo quiero trabajar</h3></div></div>
            <div className="no-print mt-4 grid gap-4 sm:grid-cols-3">
              <div><p className="text-xs font-black uppercase text-slate-500">Agrupamiento</p><div className="mt-2 flex gap-1 rounded-lg bg-sky-50 p-1"><button type="button" aria-pressed={modoTrabajo === 'individual'} onClick={() => setModoTrabajo('individual')} className={`flex-1 rounded-md px-2 py-2 text-xs font-bold ${modoTrabajo === 'individual' ? 'bg-[#0069aa] text-white' : 'text-slate-600'}`}>Individual</button><button type="button" aria-pressed={modoTrabajo === 'pareja'} onClick={() => setModoTrabajo('pareja')} className={`flex-1 rounded-md px-2 py-2 text-xs font-bold ${modoTrabajo === 'pareja' ? 'bg-[#0069aa] text-white' : 'text-slate-600'}`}>En pareja</button></div></div>
              <div><p className="text-xs font-black uppercase text-slate-500">Desafío</p><button type="button" aria-pressed={desafioAmpliado} onClick={() => setDesafioAmpliado(!desafioAmpliado)} className="mt-2 w-full rounded-lg border border-sky-200 bg-sky-50 px-3 py-2 text-left text-xs font-bold text-[#005487]">{desafioAmpliado ? (unidad.id === 'phishing' ? 'Ampliado: compara los cuatro casos' : 'Ampliado: transfiere el criterio a otro caso') : 'Básico: analiza un caso en profundidad'}</button></div>
              <div><p className="text-xs font-black uppercase text-slate-500">Nivel de apoyo</p><select value={nivelAndamiaje} onChange={(evento) => setNivelAndamiaje(Number(evento.target.value))} className="mt-2 w-full rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-xs font-bold text-amber-950" aria-label="Nivel de andamiaje"><option value={0}>0 · Sin apoyo</option><option value={1}>1 · Pregunta orientadora</option><option value={2}>2 · Lista de señales</option><option value={3}>3 · Plantilla guiada</option></select></div>
            </div>
            {nivelAndamiaje >= 1 && <div className="mt-4 border-l-4 border-amber-400 bg-amber-50 p-3 text-sm leading-6 text-amber-950"><p className="flex items-center gap-2 font-bold"><Lightbulb size={15} />Pregunta orientadora</p><p>¿Qué evidencia observable tienes, qué estás suponiendo y qué canal independiente puedes usar para verificar sin aumentar el riesgo?</p></div>}
            {nivelAndamiaje >= 2 && <div className="mt-3 bg-sky-50 p-3 text-sm text-slate-700"><p className="font-black text-slate-950">Conceptos y señales para revisar</p><ul className="mt-2 grid gap-1 sm:grid-cols-2">{unidad.conceptos.map((concepto) => <li key={concepto} className="flex items-center gap-2"><CheckCircle2 className="shrink-0 text-[#167451]" size={14} />{concepto}</li>)}<li className="flex items-center gap-2"><CheckCircle2 className="shrink-0 text-[#167451]" size={14} />Evidencia y forma de verificar</li></ul></div>}
            {nivelAndamiaje >= 3 && <div className="mt-3 overflow-x-auto"><table className="w-full border-collapse bg-white text-left text-xs"><thead><tr className="bg-slate-100"><th className="border border-slate-200 p-2">Evidencia</th><th className="border border-slate-200 p-2">Inferencia</th><th className="border border-slate-200 p-2">Dato faltante</th><th className="border border-slate-200 p-2">Verificación</th></tr></thead><tbody><tr><td className="h-12 border border-slate-200 p-2">Lo que puedo observar...</td><td className="border border-slate-200 p-2">Podría significar...</td><td className="border border-slate-200 p-2">Necesito saber...</td><td className="border border-slate-200 p-2">Consultaré...</td></tr></tbody></table></div>}
            <p className="mt-3 text-xs text-slate-500">Configuración actual: trabajo {modoTrabajo === 'pareja' ? 'en pareja' : 'individual'} · desafío {desafioAmpliado ? 'ampliado' : 'básico'} · apoyo {nivelAndamiaje}.</p>
          </section>
          <div className="mt-6 grid gap-3 rounded-lg bg-sky-50 p-4 sm:grid-cols-3"><div><p className="text-xs font-black uppercase text-slate-500">Aprenderás a</p><p className="mt-1 text-sm font-bold text-slate-900">{unidad.proposito}</p></div><div><p className="text-xs font-black uppercase text-slate-500">Producto esperado</p><p className="mt-1 text-sm font-bold text-slate-900">{unidad.producto}</p></div><div><p className="text-xs font-black uppercase text-slate-500">Tiempo estimado</p><p className="mt-1 text-sm font-bold text-slate-900">{unidad.duracion}</p></div></div>
          </section>

          <section className={`${clasePaso(1)} mt-8`}><CabeceraPaso numero={2} titulo="Identifico lo que sé" descripcion="Registra una primera decisión. No se califica: servirá para comparar cómo cambia tu respuesta." /><article className="rounded-lg border border-amber-200 bg-amber-50 p-5"><p className="text-xs font-black uppercase text-[#c65f00]">{actividades[0].momento}</p><h4 className="mt-1 text-xl font-black text-slate-950">{actividades[0].titulo}</h4><p className="mt-3 leading-7 text-slate-700"><TextoConGlosario texto={actividades[0].consigna} /></p><p className="mt-3 text-sm font-bold text-slate-700">Registra: <TextoConGlosario texto={actividades[0].evidencia} /></p></article></section>

          <section className={`${clasePaso(2)} mt-8 border-y border-sky-200 bg-white py-7`} aria-labelledby="comprender-saber">
            <CabeceraPaso numero={3} titulo="Aprendo" descripcion="Explora las ideas, ejemplos y representaciones necesarias antes de resolver el desafío." />
            <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
              <div><p className="text-xs font-black uppercase text-[#c65f00]">Comprender antes de actuar</p><h3 id="comprender-saber" className="mt-1 text-2xl font-black text-[#0069aa]">Ideas y casos clave</h3></div>
              <button type="button" onClick={alternarAudioSaber} aria-pressed={saberAudioActivo} className={`no-print inline-flex shrink-0 items-center justify-center gap-2 rounded-lg px-4 py-2 text-sm font-bold ${saberAudioActivo ? 'bg-orange-100 text-orange-900' : 'bg-[#0069aa] text-white'}`}><Volume2 size={17} />{saberAudioActivo ? 'Detener explicación' : 'Escuchar explicación'}</button>
            </div>
            <p className="mt-5 text-lg font-bold leading-8 text-slate-900"><TextoConGlosario texto={saber.ideaCentral} /></p>
            <p className="mt-3 leading-7 text-slate-700"><TextoConGlosario texto={saber.explicacion} /></p>
            <figure className="mt-6 rounded-lg border border-emerald-200 bg-emerald-50 p-5" role="img" aria-label={`Mapa visual de ${unidad.titulo}: ${saber.secuenciaVisual.join(', ')}`}>
              <figcaption className="text-xs font-black uppercase text-emerald-800">Mapa visual · Cómo razonar</figcaption>
              <div className="mt-4 grid gap-3 sm:grid-cols-[1fr_auto_1fr_auto_1fr] sm:items-stretch">
                {saber.secuenciaVisual.map((paso, indice) => <div key={paso} className="contents"><div className="flex min-h-24 flex-col justify-between rounded-lg border border-emerald-200 bg-white p-4 shadow-sm"><span className="inline-flex h-7 w-7 items-center justify-center rounded-md bg-[#167451] text-xs font-black text-white">{indice + 1}</span><p className="mt-3 text-sm font-black leading-5 text-slate-900">{paso}</p></div>{indice < saber.secuenciaVisual.length - 1 && <ChevronRight className="hidden self-center text-[#167451] sm:block" aria-hidden="true" />}</div>)}
              </div>
            </figure>
            <div className="mt-6 grid gap-4 sm:grid-cols-2">{saber.ejemplos.map((ejemplo, indice) => <article key={ejemplo.titulo} className="rounded-lg border border-sky-100 bg-sky-50 p-5"><p className="text-xs font-black uppercase text-[#c65f00]">Caso didáctico {indice + 1}</p><h4 className="mt-1 text-lg font-black text-slate-950">{ejemplo.titulo}</h4><p className="mt-3 text-sm leading-6 text-slate-700"><strong>Situación:</strong> <TextoConGlosario texto={ejemplo.situacion} /></p><p className="mt-2 text-sm leading-6 text-slate-700"><strong>Qué conviene observar:</strong> <TextoConGlosario texto={ejemplo.lectura} /></p><p className="mt-3 border-l-4 border-[#167451] pl-3 text-sm font-semibold leading-6 text-emerald-950"><strong>Decisión fundamentada:</strong> <TextoConGlosario texto={ejemplo.decision} /></p></article>)}</div>
            {(saber.ampliaciones?.length ?? 0) > 0 && <section className="mt-7 border-t border-sky-200 pt-6" aria-labelledby="ampliar-conceptos"><p className="text-xs font-black uppercase text-[#c65f00]">Para profundizar</p><h4 id="ampliar-conceptos" className="mt-1 text-xl font-black text-slate-950">Conceptos de la vida digital cotidiana</h4><div className="mt-4 grid gap-4 sm:grid-cols-2">{saber.ampliaciones?.map((ampliacion) => <article key={ampliacion.titulo} className="rounded-lg border border-amber-200 bg-amber-50 p-5"><h5 className="text-lg font-black text-slate-950"><TextoConGlosario texto={ampliacion.titulo} /></h5><p className="mt-2 text-sm leading-6 text-slate-700"><TextoConGlosario texto={ampliacion.explicacion} /></p><p className="mt-3 text-sm leading-6 text-slate-700"><strong>Ejemplo:</strong> <TextoConGlosario texto={ampliacion.ejemplo} /></p><p className="mt-3 rounded-md bg-white p-3 text-sm font-semibold leading-6 text-amber-950"><strong>Qué conviene hacer:</strong> <TextoConGlosario texto={ampliacion.cuidado} /></p></article>)}</div></section>}
            {unidad.id === 'navegacion-fuentes' && <figure className="mt-6 rounded-lg border border-slate-200 bg-slate-950 p-5 text-white" aria-labelledby="anatomia-url"><figcaption id="anatomia-url" className="font-black">Anatomía visual de una URL</figcaption><div className="mt-4 overflow-x-auto rounded-md bg-white p-4 font-mono text-sm font-bold whitespace-nowrap sm:text-base"><span className="text-[#0069aa]">https://</span><span className="text-[#c65f00]">tramites.</span><span className="text-[#167451]">gub.uy</span><span className="text-slate-700">/servicio</span><span className="text-fuchsia-700">?tema=identidad</span></div><div className="mt-4 grid gap-2 text-xs sm:grid-cols-5"><p><strong className="text-sky-300">Esquema:</strong> cómo se conecta.</p><p><strong className="text-orange-300">Subdominio:</strong> sección del sitio.</p><p><strong className="text-emerald-300">Dominio:</strong> identidad principal.</p><p><strong className="text-slate-200">Ruta:</strong> ubicación interna.</p><p><strong className="text-fuchsia-300">Parámetro:</strong> dato adicional.</p></div><div className="mt-5 grid gap-3 sm:grid-cols-2"><div className="rounded-md border border-emerald-600 bg-emerald-950 p-3"><p className="text-xs font-black uppercase text-emerald-300">Coincide con gub.uy</p><code className="mt-2 block break-all text-sm">https://tramites.<strong>gub.uy</strong>/servicio</code></div><div className="rounded-md border border-orange-500 bg-orange-950 p-3"><p className="text-xs font-black uppercase text-orange-300">Puede confundir</p><code className="mt-2 block break-all text-sm">https://gub.uy.<strong>seguridad-ejemplo.com</strong>/ingreso</code></div></div><p className="mt-4 text-sm leading-6 text-slate-200">La segunda dirección puede estar bien escrita técnicamente, pero su dominio real es <strong>seguridad-ejemplo.com</strong>. Por eso conviene hablar de una URL legítima o coherente con la institución, no solamente de una URL “válida”.</p></figure>}
            <details className="mt-7 rounded-lg border border-sky-200 bg-white p-4"><summary className="cursor-pointer font-black text-[#0069aa]">Términos usados en esta unidad · {entradasGlosario.length}</summary><dl className="mt-4 grid gap-3 sm:grid-cols-2">{entradasGlosario.map((entrada) => <div key={entrada.termino} className="border-l-4 border-sky-200 pl-3"><dt className="text-sm font-black text-slate-950">{entrada.termino}</dt><dd className="mt-1 text-sm leading-5 text-slate-600">{entrada.definicion}</dd></div>)}</dl></details>
            <p className="sr-only" aria-live="polite">{saberAudioActivo ? 'Reproduciendo explicación de la unidad.' : 'Explicación detenida.'}</p>
          </section>
          {unidad.id === 'phishing' && <section className={`${clasePaso(2)} mt-9`} aria-labelledby="casos-estudiante"><div className="flex items-end justify-between gap-4"><div><p className="text-xs font-black uppercase text-[#c65f00]">Noticias para analizar</p><h3 id="casos-estudiante" className="mt-1 text-2xl font-black text-[#0069aa]">Cuatro casos reales en Uruguay</h3></div><div className="no-print flex shrink-0 gap-2"><button type="button" onClick={() => desplazarCasos('carrusel-casos-estudiante', -1)} className="inline-flex h-10 w-10 items-center justify-center rounded-lg border border-emerald-200 bg-white text-[#167451] shadow-sm" aria-label="Caso anterior"><ChevronLeft size={20} /></button><button type="button" onClick={() => desplazarCasos('carrusel-casos-estudiante', 1)} className="inline-flex h-10 w-10 items-center justify-center rounded-lg bg-[#167451] text-white shadow-sm" aria-label="Caso siguiente"><ChevronRight size={20} /></button></div></div><p className="mt-2 text-sm leading-6 text-slate-600">Lee las reseñas y consulta las publicaciones institucionales. No abras ni reproduzcas los enlaces, adjuntos o formularios mencionados dentro de los casos.</p><div id="carrusel-casos-estudiante" className="casos-carrusel mt-5 flex gap-4 overflow-x-auto pb-5">{casosRealesPhishing.map((caso, indice) => <article key={caso.id} className="w-full shrink-0 snap-start rounded-lg border border-emerald-200 border-t-4 border-t-[#167451] bg-emerald-50 p-5 shadow-md shadow-emerald-950/10"><div className="flex items-center justify-between gap-3"><span className="rounded-md bg-[#167451] px-2 py-1 text-xs font-black text-white">Caso {indice + 1} de {casosRealesPhishing.length}</span><span className="text-xs font-bold text-emerald-800">{caso.fecha}</span></div><p className="mt-4 text-xs font-black uppercase text-[#c65f00]">{caso.institucion}</p><h4 className="mt-1 text-lg font-black text-slate-950">{caso.titulo}</h4><p className="mt-3 text-sm leading-6 text-slate-700">{caso.resumen}</p><a href={caso.fuente} target="_blank" rel="noreferrer" className="mt-4 inline-flex items-center gap-2 text-sm font-bold text-[#0069aa]">Leer publicación institucional <ExternalLink size={13} /></a></article>)}</div></section>}
          {unidad.id !== 'phishing' && <section className={`${clasePaso(2)} mt-9`} aria-labelledby="casos-estudiante-didacticos"><div className="flex items-end justify-between gap-4"><div><p className="text-xs font-black uppercase text-[#c65f00]">Casos para analizar</p><h3 id="casos-estudiante-didacticos" className="mt-1 text-2xl font-black text-[#0069aa]">Situaciones cercanas para decidir</h3></div><div className="no-print flex shrink-0 gap-2"><button type="button" onClick={() => desplazarCasos('carrusel-casos-estudiante-didacticos', -1)} className="inline-flex h-10 w-10 items-center justify-center rounded-lg border border-emerald-200 bg-white text-[#167451] shadow-sm" aria-label="Caso anterior"><ChevronLeft size={20} /></button><button type="button" onClick={() => desplazarCasos('carrusel-casos-estudiante-didacticos', 1)} className="inline-flex h-10 w-10 items-center justify-center rounded-lg bg-[#167451] text-white shadow-sm" aria-label="Caso siguiente"><ChevronRight size={20} /></button></div></div><p className="mt-2 text-sm leading-6 text-slate-600">Elige un caso. Primero registra qué harías, después revisa qué evidencia tienes y qué dato falta antes de decidir.</p><div id="carrusel-casos-estudiante-didacticos" className="casos-carrusel mt-5 flex gap-4 overflow-x-auto pb-5">{saber.ejemplos.map((caso, indice) => <article key={caso.titulo} className="w-full shrink-0 snap-start rounded-lg border border-emerald-200 border-t-4 border-t-[#167451] bg-emerald-50 p-5 shadow-md shadow-emerald-950/10"><span className="rounded-md bg-[#167451] px-2 py-1 text-xs font-black text-white">Caso {indice + 1} de {saber.ejemplos.length}</span><h4 className="mt-4 text-lg font-black text-slate-950">{caso.titulo}</h4><p className="mt-3 text-sm leading-6 text-slate-700"><strong>Situación:</strong> <TextoConGlosario texto={caso.situacion} /></p><p className="mt-3 text-sm leading-6 text-slate-700"><strong>Qué observo:</strong> <TextoConGlosario texto={caso.lectura} /></p><p className="mt-4 rounded-md bg-white p-3 text-sm font-semibold leading-6 text-emerald-950"><strong>Decisión fundamentada:</strong> <TextoConGlosario texto={caso.decision} /></p></article>)}</div></section>}

          <section className={`${clasePaso(3)} mt-8`}><CabeceraPaso numero={4} titulo="Comprendo el desafío" descripcion="Lee la situación, identifica qué debes producir y revisa con qué criterio se valorará." /><div className="border-l-4 border-[#c65f00] bg-orange-50 p-5"><h4 className="font-black text-orange-950">Situación</h4><p className="mt-2 leading-7 text-slate-700"><TextoConGlosario texto={unidad.situacion} /></p></div><div className="mt-4 grid gap-4 sm:grid-cols-2"><div className="rounded-lg border border-sky-200 bg-white p-4"><p className="text-xs font-black uppercase text-[#0069aa]">Qué debes crear</p><p className="mt-2 font-bold leading-6 text-slate-900">{unidad.producto}</p></div><div className="rounded-lg border border-emerald-200 bg-white p-4"><p className="text-xs font-black uppercase text-[#167451]">Cómo sabrás que está logrado</p><p className="mt-2 text-sm leading-6 text-slate-700"><TextoConGlosario texto={unidad.criterio} /></p></div></div></section>

          <section className={`${clasePaso(4)} mt-8`}><CabeceraPaso numero={5} titulo="Practico con apoyo" descripcion="Ensaya el procedimiento, produce una respuesta y mejórala antes de la comprobación final." /><div className="space-y-5">{actividades.slice(1).map((actividad, indice) => <article key={actividad.momento} className="rounded-lg border border-slate-200 bg-white p-5"><div className="flex gap-4"><span className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md bg-[#167451] text-sm font-black text-white">{indice + 1}</span><div><p className="text-xs font-black uppercase text-[#167451]">{actividad.momento}</p><h4 className="mt-1 text-lg font-black text-slate-950">{actividad.titulo}</h4><p className="mt-2 leading-7 text-slate-700"><TextoConGlosario texto={actividad.consigna} /></p><p className="mt-3 text-sm font-bold text-slate-700">Evidencia: <TextoConGlosario texto={actividad.evidencia} /></p></div></div></article>)}</div></section>

          <section className={`${clasePaso(5)} mt-8`}><CabeceraPaso numero={6} titulo="Consulto herramientas y fuentes" descripcion="Usa apoyos externos solo cuando aporten una evidencia útil y respeta siempre sus reglas de cuidado." />{herramientas.length === 0 && recursosAgesic.length === 0 && <p className="rounded-lg bg-sky-50 p-5 leading-7 text-slate-700">Esta unidad no necesita una herramienta externa. Continúa con la Zona Activa usando los conceptos y ejemplos trabajados.</p>}{herramientas.length > 0 && <div className="grid gap-4 lg:grid-cols-2">{herramientas.map((herramienta) => <article key={herramienta.nombre} className="rounded-lg border border-emerald-200 bg-emerald-50 p-5"><h4 className="font-black text-emerald-950">{herramienta.nombre}</h4><p className="mt-2 text-sm leading-6 text-slate-700">{herramienta.funcion}</p><p className="mt-3 text-sm leading-6 text-slate-700"><strong>Situación útil:</strong> {herramienta.situacionDidactica}</p><p className="mt-3 rounded-md bg-white p-3 text-xs font-semibold leading-5 text-orange-950"><strong>Regla de cuidado:</strong> {herramienta.reglaDeUso}</p><a href={herramienta.url} target="_blank" rel="noreferrer" className="mt-4 inline-flex items-center gap-2 text-sm font-bold text-[#0069aa]">Abrir herramienta <ExternalLink size={13} /></a></article>)}</div>}{recursosAgesic.length > 0 && <div className="mt-6"><h4 className="text-lg font-black text-slate-950">Recursos oficiales de AGESIC</h4><div className="mt-3 grid gap-3 sm:grid-cols-2">{recursosAgesic.map((recurso) => <a key={recurso.titulo} href={recurso.url} target="_blank" rel="noreferrer" className="rounded-lg border border-orange-200 bg-orange-50 p-4"><span className="flex items-center justify-between gap-3 font-black text-[#0069aa]">{recurso.titulo}<ExternalLink size={14} /></span><span className="mt-2 block text-sm leading-6 text-slate-700">{recurso.aporte}</span></a>)}</div></div>}</section>

          <section className={`${clasePaso(6)} mt-8`}><CabeceraPaso numero={7} titulo="Compruebo y cierro" descripcion="Pon a prueba tus decisiones, revisa la retroalimentación y reconoce qué cambió desde tu respuesta inicial." /><ZonaActiva ejercicios={ejercicios} /><div className="mt-8 rounded-lg border border-emerald-200 bg-emerald-50 p-5"><h4 className="font-black text-emerald-950">Cierre de la cápsula</h4><p className="mt-2 text-sm leading-6 text-slate-700"><strong>Producto final:</strong> {unidad.producto}</p><ul className="mt-4 space-y-2 text-sm leading-6 text-slate-700"><li>¿Qué decisión cambiarías respecto de tu respuesta inicial?</li><li>¿Qué evidencia sostiene ahora tu respuesta?</li><li>¿En qué otra situación podrías aplicar este criterio?</li></ul></div><LaboratorioSeguro className="mt-8" /></section>

          <nav className="no-print mt-8 flex items-center justify-between gap-3 border-t border-sky-200 pt-5" aria-label="Cambiar paso"><button type="button" onClick={() => cambiarPaso(pasoActivo - 1)} disabled={pasoActivo === 0} className="inline-flex items-center gap-2 rounded-lg border border-sky-200 bg-white px-4 py-2 text-sm font-bold text-[#0069aa] disabled:opacity-40"><ChevronLeft size={17} />Anterior</button><p className="text-center text-xs font-bold text-slate-500">Paso {pasoActivo + 1} de {pasosCapsula.length}</p><button type="button" onClick={() => cambiarPaso(pasoActivo + 1)} disabled={pasoActivo === pasosCapsula.length - 1} className="inline-flex items-center gap-2 rounded-lg bg-[#0069aa] px-4 py-2 text-sm font-bold text-white disabled:opacity-40">Siguiente<ChevronRight size={17} /></button></nav>
        </div>
        <footer className="border-t border-sky-100 bg-white px-4 py-4 text-center text-xs font-semibold text-slate-500">Recurso Educativo Abierto para estudiantes · Ciberseguridad EBI · <a href="https://creativecommons.org/licenses/by-sa/4.0/deed.es" target="_blank" rel="noreferrer" className="font-bold text-[#0069aa]">CC BY-SA 4.0</a></footer>
      </main>
    );
  }

  return (
    <main className="cyber-grid min-h-screen" data-contraste={contraste} data-texto={textoGrande ? 'grande' : 'normal'}>
      <Encabezado grado={grado} interfaz="docente" cambiarGrado={cambiarGrado} controles={controles} seccionActiva={seccionActiva} irASeccion={irASeccion} />

      <section id="fundamentacion" style={{ display: seccionActiva === 'fundamentacion' ? undefined : 'none' }} className="mx-auto max-w-6xl border-b border-sky-100 px-4 py-8 md:px-8">
        <div className="grid gap-6 lg:grid-cols-[0.36fr_1fr]"><div><p className="text-xs font-black uppercase text-[#c65f00]">Fundamentación</p><h2 className="mt-1 text-2xl font-black text-[#0069aa]">Decidir, proteger y comunicar</h2></div><div><p className="text-lg leading-8 text-slate-700">La ciberseguridad se aborda como una práctica de cuidado, análisis y responsabilidad. En consonancia con el programa de Ciencias de la Computación, se busca que el estudiantado comprenda riesgos del entorno digital, tome decisiones fundamentadas y participe de forma crítica, segura y ética.</p><p className="mt-3 leading-7 text-slate-600">La Estrategia Nacional de Ciberseguridad 2024–2030 de AGESIC destaca la necesidad de fortalecer una cultura de ciberseguridad mediante la concientización y la educación, atendiendo a la diversidad de las personas. Este recurso traduce ese propósito en situaciones cercanas, apoyos graduados y oportunidades diversas para demostrar lo aprendido.</p><p className="mt-3 leading-7 text-slate-600">El hacking ético se limita a maquetas, cuentas ficticias y sistemas propios expresamente autorizados. La intención de ayudar nunca sustituye el consentimiento, la delimitación del alcance ni el deber de no causar daño.</p><div className="mt-5 flex flex-wrap gap-3"><a href={urlPrograma} target="_blank" rel="noreferrer" className="inline-flex items-center gap-2 rounded-md border border-sky-200 bg-white px-3 py-2 text-sm font-bold text-[#0069aa]">Programa oficial ANEP <ExternalLink size={13} /></a><a href={urlCulturaCiberseguridad} target="_blank" rel="noreferrer" className="inline-flex items-center gap-2 rounded-md border border-emerald-200 bg-white px-3 py-2 text-sm font-bold text-[#167451]">Cultura de ciberseguridad · AGESIC <ExternalLink size={13} /></a></div></div></div>
      </section>

      <section id="programa" style={{ display: seccionActiva === 'programa' ? undefined : 'none' }} className="border-y border-sky-100 bg-white py-9"><div className="mx-auto grid max-w-6xl gap-6 px-4 md:px-8 lg:grid-cols-[0.36fr_1fr]"><div><p className="text-xs font-black uppercase text-[#c65f00]">Marco curricular</p><h2 className="mt-1 text-2xl font-black text-[#0069aa]">Parte del programa</h2></div><div><p className="leading-7 text-slate-700">La propuesta toma como referencia el eje Alfabetización y Ciudadanía digital de Ciencias de la Computación. Las formulaciones curriculares se distinguen de las situaciones, casos y actividades creadas por el REA.</p><div className="mt-4 border-l-4 border-[#167451] bg-emerald-50 p-4"><p className="text-sm font-black text-emerald-950">{nivel.etiqueta}</p><p className="mt-1 text-sm leading-6 text-emerald-950">{nivel.programa}</p><p className="mt-2 text-xs font-bold text-emerald-800">{nivel.tiempo}</p></div><a href={urlPrograma} target="_blank" rel="noreferrer" className="mt-4 inline-flex items-center gap-2 text-sm font-bold text-[#0069aa]">Consultar programa oficial <ExternalLink size={14} /></a></div></div></section>

      <section id="uso" style={{ display: seccionActiva === 'uso' ? undefined : 'none' }} className="mx-auto max-w-6xl scroll-mt-4 px-4 py-9 md:px-8">
        <div className="grid gap-6 lg:grid-cols-[0.36fr_1fr]">
          <div><p className="text-xs font-black uppercase text-[#c65f00]">Guía breve</p><h2 className="mt-1 text-2xl font-black text-[#0069aa]">Cómo utilizar el recurso</h2><p className="mt-3 text-sm leading-6 text-slate-600">La propuesta puede utilizarse como secuencia completa o como apoyo para una clase. La idea es partir de una situación significativa, hacer visibles los criterios de decisión y acompañar la construcción de respuestas seguras.</p></div>
          <ol className="grid gap-x-6 gap-y-5 sm:grid-cols-2">
            <li className="flex gap-3"><span className="inline-flex h-7 w-7 shrink-0 items-center justify-center rounded-md bg-[#0069aa] text-xs font-black text-white">1</span><p className="text-sm leading-6 text-slate-700"><strong>Seleccionar el nivel y la unidad.</strong> Se sugiere revisar los conocimientos previos, la dificultad frecuente y la continuidad propuesta para ubicar la actividad dentro de la planificación del grupo.</p></li>
            <li className="flex gap-3"><span className="inline-flex h-7 w-7 shrink-0 items-center justify-center rounded-md bg-[#0069aa] text-xs font-black text-white">2</span><p className="text-sm leading-6 text-slate-700"><strong>Presentar el caso como problema.</strong> La idea es recuperar primero las decisiones espontáneas del estudiantado y luego contrastarlas con evidencia y fuentes institucionales, sin utilizar enlaces o materiales riesgosos.</p></li>
            <li className="flex gap-3"><span className="inline-flex h-7 w-7 shrink-0 items-center justify-center rounded-md bg-[#0069aa] text-xs font-black text-white">3</span><p className="text-sm leading-6 text-slate-700"><strong>Ajustar la mediación.</strong> Se sugiere elegir agrupamiento, nivel de desafío y andamiaje según las necesidades del grupo, manteniendo el propósito y el criterio de logro comunes.</p></li>
            <li className="flex gap-3"><span className="inline-flex h-7 w-7 shrink-0 items-center justify-center rounded-md bg-[#0069aa] text-xs font-black text-white">4</span><p className="text-sm leading-6 text-slate-700"><strong>Compartir y recuperar evidencias.</strong> Antes de copiar el iframe a CREA, se recomienda previsualizar la ficha estudiantil. Los productos y respuestas pueden emplearse para retroalimentar, revisar decisiones y planificar la continuidad.</p></li>
          </ol>
        </div>
      </section>

      <section id="dua" style={{ display: seccionActiva === 'dua' ? undefined : 'none' }} className="border-y border-sky-100 bg-white py-9"><div className="mx-auto grid max-w-6xl gap-6 px-4 md:px-8 lg:grid-cols-[0.36fr_1fr]"><div><p className="text-xs font-black uppercase text-[#c65f00]">Diseño Universal</p><h2 className="mt-1 text-2xl font-black text-[#0069aa]">Enfoque DUA</h2><p className="mt-2 text-sm leading-6 text-slate-600">El objetivo y el criterio se mantienen; cambian los apoyos y las formas de acceso y respuesta.</p></div><div className="grid gap-5 md:grid-cols-3"><div><Users className="text-[#167451]" size={22} /><h3 className="mt-2 font-black text-slate-950">Implicación</h3><p className="mt-2 text-sm leading-6 text-slate-600">Casos uruguayos, elección de rol, trabajo individual o en pareja y desafío básico o ampliado.</p></div><div><MonitorSmartphone className="text-[#0069aa]" size={22} /><h3 className="mt-2 font-black text-slate-950">Representación</h3><p className="mt-2 text-sm leading-6 text-slate-600">Noticia original, síntesis, señales, árbol de decisión, lectura clara y vocabulario contextual.</p></div><div><FileText className="text-[#c65f00]" size={22} /><h3 className="mt-2 font-black text-slate-950">Acción y expresión</h3><p className="mt-2 text-sm leading-6 text-slate-600">Reporte, audio, tabla, protocolo, diagrama o explicación oral con el mismo criterio de seguridad.</p></div></div></div></section>

      {seccionActiva === 'etica' && <LaboratorioSeguro id="etica" />}

      <section id="progresion" style={{ display: seccionActiva === 'unidades' ? undefined : 'none' }} className="mx-auto max-w-6xl scroll-mt-4 px-4 py-9 md:px-8">
        <div className="grid gap-6 lg:grid-cols-[0.36fr_1fr]"><div><p className="text-xs font-black uppercase text-[#c65f00]">Matriz curricular</p><h2 className="mt-1 text-2xl font-black text-[#0069aa]">Progresión 7.º–9.º</h2></div><div className="overflow-x-auto"><table className="w-full border-collapse text-left text-sm"><thead><tr className="border-b-2 border-[#0069aa]"><th className="p-3">Nivel</th><th className="p-3">Enfoque</th><th className="p-3">Desempeño esperado</th></tr></thead><tbody>{grados.map((item) => <tr key={item} className="border-b border-slate-200"><th className="p-3 font-black text-[#0069aa]">{niveles[item].etiqueta}</th><td className="p-3 leading-6 text-slate-700">{niveles[item].enfoque}</td><td className="p-3 leading-6 text-slate-700">{item === '7mo' ? 'Reconoce y protege.' : item === '8vo' ? 'Detecta y responde.' : 'Diseña y audita con autorización.'}</td></tr>)}</tbody></table></div></div>
      </section>

      {seccionActiva === 'unidades' && <section id="casos" className="scroll-mt-4 border-y border-emerald-100 bg-white py-9"><div className="mx-auto max-w-6xl px-4 md:px-8"><div className="flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between"><div><p className="text-xs font-black uppercase text-[#c65f00]">Metodología basada en casos</p><h2 className="mt-1 text-2xl font-black text-[#0069aa]">Casos para enseñar {unidad.titulo.toLowerCase()}</h2><p className="mt-3 max-w-3xl text-sm leading-6 text-slate-600">{unidad.id === 'phishing' ? 'Estos casos provienen de publicaciones institucionales y se recrean sin enlaces activos, códigos, formularios ni datos reales.' : 'Estos casos didácticos presentan situaciones posibles y cercanas. No describen personas ni hechos identificables; permiten analizar decisiones sin exponer datos o sistemas reales.'}</p><p className="mt-2 max-w-3xl text-sm font-semibold leading-6 text-emerald-900">Se sugiere presentar primero la situación, recoger decisiones iniciales y recién después ofrecer las pistas y la decisión fundamentada.</p></div><div className="no-print flex shrink-0 gap-2"><button type="button" onClick={() => desplazarCasos(`carrusel-casos-docente-${unidad.id}`, -1)} className="inline-flex h-11 w-11 items-center justify-center rounded-lg border border-emerald-200 bg-white text-[#167451] shadow-sm" aria-label="Caso anterior" title="Caso anterior"><ChevronLeft size={21} /></button><button type="button" onClick={() => desplazarCasos(`carrusel-casos-docente-${unidad.id}`, 1)} className="inline-flex h-11 w-11 items-center justify-center rounded-lg bg-[#167451] text-white shadow-sm" aria-label="Caso siguiente" title="Caso siguiente"><ChevronRight size={21} /></button></div></div><div id={`carrusel-casos-docente-${unidad.id}`} className="casos-carrusel mt-6 flex gap-5 overflow-x-auto pb-6">{unidad.id === 'phishing' ? casosRealesPhishing.map((caso, indice) => <article key={caso.id} className="w-full shrink-0 snap-start rounded-lg border border-emerald-200 border-t-4 border-t-[#167451] bg-emerald-50 p-5 shadow-lg shadow-emerald-950/10 sm:p-6"><div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between"><div><div className="flex flex-wrap items-center gap-2"><span className="rounded-md bg-[#167451] px-2 py-1 text-xs font-black text-white">Caso real {indice + 1} de {casosRealesPhishing.length}</span><span className="text-xs font-bold text-emerald-800">{caso.fecha}</span></div><h3 className="mt-3 text-xl font-black text-slate-950">{caso.titulo}</h3><p className="mt-1 text-sm font-bold text-[#0069aa]">{caso.institucion}</p></div><a href={caso.fuente} target="_blank" rel="noreferrer" className="inline-flex shrink-0 items-center gap-2 rounded-md border border-sky-200 bg-white px-3 py-2 text-xs font-bold text-[#0069aa] shadow-sm">Abrir noticia <ExternalLink size={13} /></a></div><p className="mt-4 text-sm leading-6 text-slate-700">{caso.resumen}</p><div className="mt-5 grid gap-5 border-t border-emerald-200 pt-5 md:grid-cols-2"><div><h4 className="text-sm font-black text-slate-950">Estrategia o problema central</h4><p className="mt-1 text-sm leading-6 text-slate-600">{caso.estrategia}</p><h4 className="mt-4 text-sm font-black text-slate-950">Señales observables</h4><ul className="mt-2 space-y-1">{caso.senales.map((senal) => <li key={senal} className="flex gap-2 text-sm leading-5 text-slate-600"><CheckCircle2 className="mt-0.5 shrink-0 text-[#167451]" size={14} />{senal}</li>)}</ul></div><div><h4 className="text-sm font-black text-slate-950">Decisión fundamentada</h4><p className="mt-1 text-sm leading-6 text-slate-600">{caso.decisionSegura}</p><h4 className="mt-4 text-sm font-black text-slate-950">Actividad práctica</h4><p className="mt-1 text-sm leading-6 text-slate-600">{caso.practica}</p></div></div><details className="mt-5 border-t border-emerald-200 pt-4" open><summary className="cursor-pointer text-sm font-bold text-[#0069aa]">Preguntas para la mediación docente</summary><ul className="mt-2 space-y-2">{caso.preguntasDocentes.map((pregunta) => <li key={pregunta} className="text-sm leading-6 text-slate-700">{pregunta}</li>)}</ul></details></article>) : saber.ejemplos.map((caso, indice) => <article key={caso.titulo} className="w-full shrink-0 snap-start rounded-lg border border-emerald-200 border-t-4 border-t-[#167451] bg-emerald-50 p-5 shadow-lg shadow-emerald-950/10 sm:p-6"><span className="rounded-md bg-[#167451] px-2 py-1 text-xs font-black text-white">Caso didáctico {indice + 1} de {saber.ejemplos.length}</span><h3 className="mt-4 text-xl font-black text-slate-950">{caso.titulo}</h3><p className="mt-3 text-sm leading-6 text-slate-700"><strong>Situación para presentar:</strong> {caso.situacion}</p><div className="mt-5 grid gap-5 border-t border-emerald-200 pt-5 md:grid-cols-2"><div><h4 className="text-sm font-black text-slate-950">Qué conviene observar</h4><p className="mt-1 text-sm leading-6 text-slate-600">{caso.lectura}</p><h4 className="mt-4 text-sm font-black text-slate-950">Conceptos para recuperar</h4><p className="mt-1 text-sm leading-6 text-slate-600">{unidad.conceptos.join(', ')}.</p></div><div><h4 className="text-sm font-black text-slate-950">Decisión fundamentada</h4><p className="mt-1 text-sm leading-6 text-slate-600">{caso.decision}</p><h4 className="mt-4 text-sm font-black text-slate-950">Actividad práctica</h4><p className="mt-1 text-sm leading-6 text-slate-600">Comparar la decisión inicial con la decisión fundamentada y representar una alternativa mediante una tabla, audio, diagrama o explicación breve.</p></div></div><details className="mt-5 border-t border-emerald-200 pt-4" open><summary className="cursor-pointer text-sm font-bold text-[#0069aa]">Preguntas para la mediación docente</summary><ul className="mt-2 space-y-2 text-sm leading-6 text-slate-700"><li>¿Qué información conocemos y cuál todavía falta?</li><li>¿Qué parte de la respuesta es evidencia y cuál es una suposición?</li><li>¿Qué decisión reduce el riesgo sin perjudicar a otras personas?</li></ul></details></article>)}</div></div></section>}

      <section id="unidades" style={{ display: seccionActiva === 'unidades' ? undefined : 'none' }} className="border-y border-sky-100 bg-white py-9"><div className="mx-auto max-w-6xl px-4 md:px-8"><div className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between"><div><p className="text-xs font-black uppercase text-[#c65f00]">{nivel.etiqueta}</p><h2 className="mt-1 text-2xl font-black text-[#0069aa]">Unidades del nivel</h2><p className="mt-2 max-w-3xl text-sm leading-6 text-slate-600">{nivel.programa}</p></div><span className="text-xs font-bold text-slate-500">{nivel.tiempo}</span></div><div className="mt-6 grid gap-3 sm:grid-cols-2 lg:grid-cols-4">{nivel.unidades.map((item, indice) => <button key={item.id} type="button" aria-pressed={unidad.id === item.id} onClick={() => navegar({ unidad: item.id })} className={`min-h-28 rounded-lg border p-4 text-left transition ${unidad.id === item.id ? 'border-[#0069aa] bg-[#0069aa] text-white' : 'border-slate-200 bg-slate-50 text-slate-800 hover:border-sky-400'}`}><span className={`text-xs font-black uppercase ${unidad.id === item.id ? 'text-sky-100' : 'text-[#c65f00]'}`}>Unidad {indice + 1}</span><span className="mt-2 block font-black leading-5">{item.titulo}</span></button>)}</div></div></section>

      <section id="ficha" style={{ display: seccionActiva === 'unidades' ? undefined : 'none' }} className="mx-auto max-w-6xl scroll-mt-4 px-4 py-9 md:px-8">
        <div className="flex flex-col gap-4 border-b-4 border-[#167451] pb-6 sm:flex-row sm:items-start sm:justify-between"><div><p className="text-xs font-black uppercase text-[#c65f00]">Ficha docente y versión embebible</p><h2 className="mt-1 text-2xl font-black text-slate-950">{unidad.titulo}</h2><p className="mt-2 max-w-3xl leading-7 text-slate-700">{unidad.proposito}</p></div><div className="no-print grid grid-cols-2 gap-2 sm:flex"><button type="button" onClick={() => navegar({ interfaz: 'alumno', agrupamiento: modoTrabajo, desafio: desafioAmpliado ? 'ampliado' : 'basico', andamiaje: String(nivelAndamiaje) })} className="inline-flex items-center justify-center gap-2 rounded-lg bg-[#0069aa] px-3 py-2 text-xs font-bold text-white"><Eye size={14} />Previsualizar</button><button type="button" onClick={copiarIframe} className="inline-flex items-center justify-center gap-2 rounded-lg border border-sky-200 bg-white px-3 py-2 text-xs font-bold text-[#0069aa]"><Copy size={14} />Iframe CREA</button><button type="button" onClick={() => descargar(htmlFicha(unidad), `ficha-${grado}-${unidad.id}.html`)} className="inline-flex items-center justify-center gap-2 rounded-lg border border-emerald-200 bg-white px-3 py-2 text-xs font-bold text-emerald-800"><Download size={14} />Ficha HTML</button><button type="button" onClick={() => window.print()} className="inline-flex items-center justify-center gap-2 rounded-lg border border-orange-200 bg-white px-3 py-2 text-xs font-bold text-orange-800"><Printer size={14} />Imprimir</button></div></div>
        {estadoCopia && <p className="mt-3 rounded-lg bg-emerald-50 p-3 text-sm font-bold text-emerald-800" aria-live="polite">{estadoCopia}</p>}
        <section className="no-print mt-6 border-y border-sky-200 bg-white py-5" aria-labelledby="personalizar-crea">
          <div className="flex items-center gap-3"><Accessibility className="text-[#0069aa]" size={22} /><div><p className="text-xs font-black uppercase text-[#c65f00]">Configuración embebible</p><h3 id="personalizar-crea" className="font-black text-slate-950">Personalización DUA para CREA</h3></div></div>
          <div className="mt-4 grid gap-4 md:grid-cols-3">
            <fieldset><legend className="text-xs font-black uppercase text-slate-500">Agrupamiento</legend><div className="mt-2 flex rounded-lg bg-sky-50 p-1"><button type="button" onClick={() => setModoTrabajo('individual')} className={`flex-1 rounded-md px-3 py-2 text-xs font-bold ${modoTrabajo === 'individual' ? 'bg-[#0069aa] text-white' : 'text-slate-600'}`} aria-pressed={modoTrabajo === 'individual'}><UserRound className="mr-1 inline" size={14} />Individual</button><button type="button" onClick={() => setModoTrabajo('pareja')} className={`flex-1 rounded-md px-3 py-2 text-xs font-bold ${modoTrabajo === 'pareja' ? 'bg-[#0069aa] text-white' : 'text-slate-600'}`} aria-pressed={modoTrabajo === 'pareja'}><Users className="mr-1 inline" size={14} />En pareja</button></div></fieldset>
            <fieldset><legend className="text-xs font-black uppercase text-slate-500">Nivel de desafío</legend><div className="mt-2 flex rounded-lg bg-sky-50 p-1"><button type="button" onClick={() => setDesafioAmpliado(false)} className={`flex-1 rounded-md px-3 py-2 text-xs font-bold ${!desafioAmpliado ? 'bg-[#0069aa] text-white' : 'text-slate-600'}`} aria-pressed={!desafioAmpliado}>Básico</button><button type="button" onClick={() => setDesafioAmpliado(true)} className={`flex-1 rounded-md px-3 py-2 text-xs font-bold ${desafioAmpliado ? 'bg-[#0069aa] text-white' : 'text-slate-600'}`} aria-pressed={desafioAmpliado}>Ampliado</button></div></fieldset>
            <label className="text-xs font-black uppercase text-slate-500">Nivel de andamiaje<select value={nivelAndamiaje} onChange={(evento) => setNivelAndamiaje(Number(evento.target.value))} className="mt-2 block w-full rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-xs font-bold normal-case text-amber-950"><option value={0}>0 · Sin apoyo adicional</option><option value={1}>1 · Pregunta orientadora</option><option value={2}>2 · Lista de señales</option><option value={3}>3 · Plantilla guiada</option></select></label>
          </div>
          <p className="mt-4 text-sm leading-6 text-slate-600">El iframe conservará esta configuración: trabajo <strong>{modoTrabajo === 'pareja' ? 'en pareja' : 'individual'}</strong>, desafío <strong>{desafioAmpliado ? 'ampliado' : 'básico'}</strong> y andamiaje <strong>{nivelAndamiaje}</strong>. El estudiante podrá ajustarla si necesita otra forma de acceso.</p>
        </section>
        <dl className="mt-6 grid gap-5 sm:grid-cols-2 lg:grid-cols-4"><div><dt className="text-xs font-black uppercase text-slate-500">Previos</dt><dd className="mt-1 text-sm leading-6 text-slate-700">{unidad.previos}</dd></div><div><dt className="text-xs font-black uppercase text-slate-500">Dificultad frecuente</dt><dd className="mt-1 text-sm leading-6 text-slate-700">{unidad.dificultad}</dd></div><div><dt className="text-xs font-black uppercase text-slate-500">Evidencia</dt><dd className="mt-1 text-sm leading-6 text-slate-700">{unidad.evidencia}</dd></div><div><dt className="text-xs font-black uppercase text-slate-500">Continuidad</dt><dd className="mt-1 text-sm leading-6 text-slate-700">{unidad.continuidad}</dd></div></dl>
        <div className="mt-6 grid gap-5 border-t border-slate-200 pt-6 lg:grid-cols-2"><div><h3 className="font-black text-slate-950">Vinculación curricular</h3><p className="mt-2 text-sm leading-6 text-slate-600">{unidad.referenciaPrograma}</p><ul className="mt-3 space-y-2">{unidad.contenidosPrograma.map((contenido) => <li key={contenido} className="flex gap-2 text-sm text-slate-700"><CheckCircle2 className="mt-0.5 shrink-0 text-[#167451]" size={16} />{contenido}</li>)}</ul></div><div><h3 className="font-black text-slate-950">Situación y producto</h3><p className="mt-2 text-sm leading-6 text-slate-700">{unidad.situacion}</p><p className="mt-3 text-sm font-bold text-[#0069aa]">Producto: {unidad.producto}</p><p className="mt-2 text-sm leading-6 text-slate-600">Criterio: {unidad.criterio}</p></div></div>
      </section>

      <section id="actividades" style={{ display: seccionActiva === 'unidades' ? undefined : 'none' }} className="border-t border-sky-100 bg-white py-9"><div className="mx-auto max-w-6xl px-4 md:px-8"><div className="flex items-center gap-3"><Route className="text-[#167451]" /><div><p className="text-xs font-black uppercase text-[#c65f00]">Secuencia sugerida</p><h2 className="text-2xl font-black text-[#0069aa]">Cuatro momentos</h2></div></div><div className="mt-6 grid gap-4 md:grid-cols-2">{actividades.map((actividad, indice) => <article key={actividad.momento} className="rounded-lg border border-slate-200 bg-slate-50 p-5"><div className="flex gap-3"><span className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md bg-[#167451] text-sm font-black text-white">{indice + 1}</span><div><p className="text-xs font-black uppercase text-[#c65f00]">{actividad.momento}</p><h3 className="mt-1 font-black text-slate-950">{actividad.titulo}</h3><p className="mt-2 text-sm leading-6 text-slate-700">{actividad.consigna}</p><p className="mt-3 text-xs font-bold text-slate-600">Evidencia: {actividad.evidencia}</p><div className="mt-4 border-t border-slate-200 pt-3"><p className="text-xs font-black uppercase text-[#0069aa]">Sugerencias docentes</p><p className="mt-2 text-sm leading-6 text-slate-700">{sugerenciasDocentes[indice]}</p><p className="mt-2 text-xs leading-5 text-slate-500">DUA: permite respuesta oral, escrita, visual o sonora; ofrece el nivel de andamiaje necesario y conserva el mismo criterio de logro.</p></div></div></div></article>)}</div></div></section>

      <section style={{ display: seccionActiva === 'unidades' ? undefined : 'none' }} className="mx-auto max-w-4xl px-4 py-10 md:px-8"><ZonaActiva ejercicios={ejercicios} /></section>
      <section className="border-t border-sky-100 bg-white px-4 py-7 print:hidden" aria-labelledby="metadatos-rea"><div className="mx-auto max-w-6xl md:px-4"><h2 id="metadatos-rea" className="text-lg font-black text-[#0069aa]">Información del Recurso Educativo Abierto</h2><dl className="mt-4 grid gap-4 text-sm sm:grid-cols-2 lg:grid-cols-4"><div className="flex gap-3"><UserRound className="shrink-0 text-[#f7941d]" size={18} /><div><dt className="font-black text-slate-950">Autoría</dt><dd className="mt-1 leading-6 text-slate-600"><span className="block">Prof. Esp. Santiago Hernández.</span><span className="block">Contenidista de Informática de DGES-ANEP.</span><span className="mt-1 block font-semibold text-slate-700">Recurso validado por Inspección de Informática.</span><span className="block">2026.</span></dd></div></div><div className="flex gap-3"><CreativeCommons className="shrink-0 text-[#f7941d]" size={18} /><div><dt className="font-black text-slate-950">Licencia</dt><dd className="mt-1 leading-6 text-slate-600"><a href="https://creativecommons.org/licenses/by-sa/4.0/deed.es" target="_blank" rel="noreferrer" className="font-bold text-[#0069aa]">CC BY-SA 4.0 <ExternalLink className="inline" size={13} /></a></dd></div></div><div className="flex gap-3"><CalendarDays className="shrink-0 text-[#f7941d]" size={18} /><div><dt className="font-black text-slate-950">Versión</dt><dd className="mt-1 leading-6 text-slate-600">0.1 · 30 de junio de 2026 · Ciberseguridad EBI.</dd></div></div><div className="flex gap-3"><Code2 className="shrink-0 text-[#f7941d]" size={18} /><div><dt className="font-black text-slate-950">Fuentes editables</dt><dd className="mt-1 leading-6 text-slate-600">TypeScript y Markdown. Cada unidad permite descargar su ficha estructurada.</dd></div></div></dl><div className="mt-5 grid gap-4 border-t border-sky-100 pt-4 md:grid-cols-2"><div className="flex gap-3"><BookOpen className="mt-1 shrink-0 text-[#f7941d]" size={18} /><div><h3 className="font-black text-slate-950">Bibliografía curricular</h3><a href={urlPrograma} target="_blank" rel="noreferrer" className="mt-1 inline-flex items-center gap-2 text-sm font-bold text-[#0069aa]">Programa oficial ANEP <ExternalLink size={13} /></a><p className="mt-1 text-xs leading-5 text-slate-500">ANEP, Ciencias de la Computación, ajustes 2024.</p></div></div><div><h3 className="font-black text-slate-950">Atribuciones</h3><p className="mt-1 text-xs leading-5 text-slate-600">Las noticias institucionales se enlazan como referencias y conservan las condiciones de sus publicaciones originales. Las recreaciones educativas no incorporan datos personales, credenciales ni enlaces maliciosos activos.</p></div></div></div></section>
      <footer className="border-t border-sky-100 bg-white px-4 py-4 text-center text-xs font-semibold text-slate-500">Recurso Educativo Abierto para docentes · Ciberseguridad EBI · {nivel.etiqueta}</footer>
    </main>
  );
}
